@rendermode InteractiveServer
@inject CascadingValueSource<WarehouseInfo> WarehouseSource
@using sv_703fbe1c5c2747a39e9ea21630dd709b.Services

<select class="form-select form-select-sm" style="width: 200px;"
        value="@_selectedId" @onchange="OnWarehouseChanged">
    @foreach (var (id, name) in WarehouseInfo.AvailableWarehouses)
    {
        <option value="@id">@name</option>
    }
</select>

@code {
    private string _selectedId = "WH-001";

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        _selectedId = e.Value?.ToString() ?? "WH-001";
        var match = WarehouseInfo.AvailableWarehouses
            .FirstOrDefault(w => w.Id == _selectedId);

        await WarehouseSource.NotifyChangedAsync(new WarehouseInfo
        {
            WarehouseId = match.Id,
            WarehouseName = match.Name
        });
    }
}

@rendermode InteractiveServer
@inject AlertState AlertState
@implements IDisposable
@using sv_703fbe1c5c2747a39e9ea21630dd709b.Services

@if (AlertState.LowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill">@AlertState.LowStockCount</span>
}
else
{
    <span class="badge bg-success rounded-pill">0</span>
}

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertState.OnChange += _handler;
    }

    public void Dispose()
    {
        AlertState.OnChange -= _handler;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@inject InventoryAlertService InventoryAlertService
@inject AlertState AlertState
@implements IAsyncDisposable
@using sv_703fbe1c5c2747a39e9ea21630dd709b.Services

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Current Warehouse</h5>
                <p class="card-text fs-4">
                    <strong>@Warehouse?.WarehouseName</strong>
                    <span class="text-muted">(@Warehouse?.WarehouseId)</span>
                </p>
            </div>
        </div>
    </div>
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Low Stock Alerts</h5>
                <p class="card-text fs-4">
                    @if (AlertState.LowStockCount > 0)
                    {
                        <span class="text-danger fw-bold">
                            ⚠ @AlertState.LowStockCount items below minimum level
                        </span>
                    }
                    else
                    {
                        <span class="text-success fw-bold">
                            ✓ All items adequately stocked
                        </span>
                    }
                </p>
                <p class="text-muted small">
                    Polling every 10 seconds &bull; Last check: @_lastCheck?.ToString("HH:mm:ss")
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseInfo? Warehouse { get; set; }

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private DateTime? _lastCheck;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        // Subscribe so this component also re-renders when AlertState changes
        // (even though we are the one triggering most updates, it keeps us
        // in sync if another component ever pushes an update).
        _alertHandler = () => InvokeAsync(StateHasChanged);
        AlertState.OnChange += _alertHandler;
    }

    protected override async Task OnParametersSetAsync()
    {
        // Restart polling whenever the warehouse changes
        await StopPollingAsync();
        await PollOnceAsync();
        StartPolling();
    }

    private void StartPolling()
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await PollOnceAsync();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on disposal or warehouse change
        }
    }

    private async Task PollOnceAsync()
    {
        if (Warehouse is null) return;
        var count = await InventoryAlertService.GetLowStockCountAsync(Warehouse.WarehouseId);
        _lastCheck = DateTime.Now;
        // Push to the shared AlertState — this notifies ALL subscribers
        AlertState.SetLowStockCount(count);
    }

    private async Task StopPollingAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
        _timer?.Dispose();
        _timer = null;
    }

    public async ValueTask DisposeAsync()
    {
        AlertState.OnChange -= _alertHandler;
        await StopPollingAsync();
    }
}

